import scala.collection.mutable.PriorityQueue

def solve(edges: Array[Array[Long]], online: Array[Boolean], k: Long): Long = {
  val n = online.length
  val adj = Array.fill(n)(Array[(Int, Long)]())
  for (edge <- edges) {
    val u = edge(0).toInt
    val v = edge(1).toInt
    val cost = edge(2)
    if (online(v)) {
      adj(u) :+= (v, cost)
    }
  }

  val max_min = Array.fill(n)(-Long.MaxValue)
  val pq = PriorityQueue[(Long, Long, Int)]()
  for ((v, cost) <- adj(0)) {
    if (max_min(v) < cost) {
      max_min(v) = cost
      pq += (-cost, cost, v)
    }
  }

  while (pq.nonEmpty) {
    val (neg_curr_min, total, node) = pq.pop()
    val curr_min = -neg_curr_min
    if (node == n - 1) return curr_min
    for ((v, cost) <- adj(node)) {
      val new_min = math.min(curr_min, cost)
      val new_total = total + cost
      if (new_total > k) {
        // Skip this edge
      } else {
        if (new_min > max_min(v)) {
          max_min(v) = new_min
          pq += (-new_min, new_total, v)
        }
      }
    }
  }
  -1
}
